mapper.select:
select r.relation_id, r.inviter_id, r.invitee_id, r.invite_code, r.invite_status, r.invite_time, r.certified_time,
    r.create_by, r.create_time, r.update_by, r.update_time, r.remark,
    inviter.nickname as inviter_name, inviter.phone as inviter_phone,
    invitee.nickname as invitee_name, invitee.phone as invitee_phone
from biz_invite_relation r
    left join biz_miniapp_user inviter on inviter.user_id = r.inviter_id
    left join biz_miniapp_user invitee on invitee.user_id = r.invitee_id


        AND r.inviter_id = #{inviterId}


        AND r.invitee_id = #{inviteeId}


        AND r.invite_status = #{inviteStatus}


        AND r.invite_code = #{inviteCode}


order by r.relation_id desc

mapper.update:
update biz_invite_relation
inviter_id = #{inviterId}, invitee_id = #{inviteeId}, invite_code = #{inviteCode}, invite_status = #{inviteStatus}, invite_time = #{inviteTime}, certified_time = #{certifiedTime}, remark = #{remark}, update_by = #{updateBy}, update_time = sysdate()
where relation_id = #{relationId}
